code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Button, Badge, Separator, icon } from 'decantr/components';

code.example:
function PricingTable() {
  const { div, span, h3, ul, li } = tags;
  const plans = [
    { name: 'Starter', price: 9, featured: false, features: ['5 projects', '1 GB storage', 'Email support'] },
    { name: 'Pro', price: 29, featured: true, features: ['Unlimited projects', '10 GB storage', 'Priority support', 'API access', 'Custom domain'] },
    { name: 'Enterprise', price: 99, featured: false, features: ['Everything in Pro', '100 GB storage', 'Dedicated support', 'SSO', 'Audit logs', 'SLA'] }
  ];

  return div({ class: css('_grid _gc3 _gap6 _p4 _aic') },
    ...plans.map(plan =>
      Card({ class: css(plan.featured ? '_b2 _bcprimary' : '') },
        Card.Header({ class: css('_tc') },
          plan.featured ? Badge({ variant: 'primary', class: css('_mb2') }, 'Popular') : null,
          h3({ class: css('_heading4') }, plan.name),
          div({ class: css('_mt2') },
            span({ class: css('_heading1') }, `$${plan.price}`),
            span({ class: css('_fgmuted') }, '/month')
          )
        ),
        Separator(),
        Card.Body({},
          ul({ class: css('_flex _col _gap2') },
            ...plan.features.map(f =>
              li({ class: css('_flex _aic _gap2 _textsm') }, icon('check', { class: css('_fgsuccess') }), f)
            )
          )
        ),
        Card.Footer({},
          Button({ variant: plan.featured ? 'primary' : 'outline', class: css('_wfull') }, 'Get Started')
        )
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Card, Separator, icon } from 'decantr/components';

code.example:
function FeatureComparison({ plans, features }) {
  const { div, span, table, thead, tbody, tr, th, td } = tags;

  return Card({},
    Card.Body({ class: css('_overflow[auto]') },
      table({ class: css('_wfull _textLeft') },
        thead({},
          tr({ class: css('_borderB') },
            th({ class: css('_p3 _textsm _fgmuted') }, 'Feature'),
            ...plans.map(p => th({ class: css('_p3 _tc') },
              div({ class: css('_flex _col _aic _gap1') },
                span({ class: css('_textsm _bold') }, p.name),
                p.featured ? Badge({ variant: 'primary', size: 'sm' }, 'Popular') : null
              )
            ))
          )
        ),
        tbody({},
          ...features.map(feat =>
            tr({ class: css('_borderB') },
              td({ class: css('_p3 _textsm') }, feat.name),
              ...plans.map(p => td({ class: css('_p3 _tc') },
                feat.values[p.id] ? icon('check', { class: css('_fgsuccess') }) : icon('x', { class: css('_fgmuted/40') })
              ))
            )
          )
        )
      )
    )
  );
}

